layer_meta = {
    "hurt":       ("For the hurt you're carrying",        "tag-hurt",       "layer-hurt"),
    "fear":       ("About my fear",                       "tag-fear",       "layer-fear"),
    "confession": ("What I need to confess",              "tag-confession", "layer-confession"),
    "hope":       ("What I hope for us",                  "tag-hope",       "layer-hope"),
    "love":       ("How deeply I love you",               "tag-love",       "layer-love"),
    "choice":     ("My choice, every single day",         "tag-choice",     "layer-choice"),
    "backburner": ("For what you quietly carried for me", "tag-backburner", "layer-backburner"),
}
layers_order = ["hurt", "fear", "confession", "hope", "love", "choice"]
TOTAL_STEPS = len(layers_order)

closings = [
    "I'm here. I'm not going anywhere.",
    "You don't have to hold this alone.",
    "This is me, staying.",
    "Right here. Always.",
    "I mean every word.",
    "Every single word of this is true.",
    "This is my heart, unguarded.",
]

# ─── SESSION STATE ─────────────────────────────────────────────────────────────
if "step" not in st.session_state:
    st.session_state.step = 0
if "cards" not in st.session_state:
    st.session_state.cards = []

# ─── HERO ─────────────────────────────────────────────────────────────────────
st.markdown("""
<div class="hero">
  <span class="hero-heart">🤍</span>
  <div class="hero-title">For You</div>
  <div class="hero-subtitle">
    If you're hurting right now —<br>
    come a little closer. Let me hold this with you.
  </div>
  <div style="margin-top: 1.4rem; font-family: 'Cormorant Garamond', serif; font-style: italic; font-size: 1.55rem; font-weight: 300; color: rgba(247, 214, 224, 0.55); letter-spacing: 0.08em;">
    I love you.
  </div>
</div>
""", unsafe_allow_html=True)

# ─── EMOTION SELECTOR ─────────────────────────────────────────────────────────
st.markdown('<div class="emotion-section-label">What does it feel like right now?</div>', unsafe_allow_html=True)

emotion = st.radio(
    "",
    ["💔 Deeply hurt", "😞 Confused & lost", "😔 Quietly hurting", "🕯️ On the back burner"],
    horizontal=True,
    label_visibility="collapsed",
)

st.markdown("<br>", unsafe_allow_html=True)

# ─── PROGRESS DOTS ────────────────────────────────────────────────────────────
def render_progress(step):
    segs = ""
    for i in range(TOTAL_STEPS):
        cls = "done" if i < step else "pending"
        segs += f'<div class="progress-seg {cls}"></div>'
    st.markdown(f'<div class="progress-wrap">{segs}</div>', unsafe_allow_html=True)

render_progress(st.session_state.step)

# ─── PREVIOUS CARDS ───────────────────────────────────────────────────────────
for card in st.session_state.cards:
    label, tag_cls, card_cls = layer_meta[card["layer"]]
    st.markdown(f"""
    <div class="msg-wrapper">
      <span class="msg-layer-tag {tag_cls}">{label}</span>
      <div class="msg-card {card_cls}">
        <div class="msg-quote">"{card['msg']}"</div>
        <div class="msg-closing">{card['closing']}</div>
      </div>
    </div>
    """, unsafe_allow_html=True)

# ─── COMPLETION ───────────────────────────────────────────────────────────────
if st.session_state.step >= TOTAL_STEPS:
    st.markdown("""
    <div class="completion-glow">
      <span class="completion-icon">🌿</span>
      <div class="completion-title">You've heard everything I needed to say.</div>
      <div class="completion-sub">
        Thank you for staying. Thank you for listening.<br>
        I love you — not perfectly, but completely.
      </div>
    </div>
    """, unsafe_allow_html=True)

# ─── BUTTONS ──────────────────────────────────────────────────────────────────
col1, col2 = st.columns([3, 1])

with col1:
    btn_label = "Hold me through this  💛" if st.session_state.step < TOTAL_STEPS else "You've heard it all 🤍"
    hold = st.button(btn_label, disabled=(st.session_state.step >= TOTAL_STEPS), use_container_width=True)

with col2:
    reset = st.button("Start over", use_container_width=True)

# ─── LOGIC ────────────────────────────────────────────────────────────────────
if hold and st.session_state.step < TOTAL_STEPS:
    layer = layers_order[st.session_state.step]
    if layer == "hurt":
        pool = messages["hurt"][emotion]
        display_layer = "backburner" if emotion == "🕯️ On the back burner" else "hurt"
    else:
        pool = messages[layer]
        display_layer = layer
    msg = random.choice(pool)
    closing = random.choice(closings)
    st.session_state.cards.append({"layer": display_layer, "msg": msg, "closing": closing})
    st.session_state.step += 1
    st.rerun()

if reset:
    st.session_state.step = 0
    st.session_state.cards = []
    st.rerun()

# ─── FOOTER ───────────────────────────────────────────────────────────────────
st.markdown("""
<div class="footer-verse">
  Even when fear is the loudest thing in the room —<br>
  there is a part of me that will always find its way back to you.
</div>
""", unsafe_allow_html=True)